                "longitude": { "type": "number" },
                "latitude": { "type": "number" },
                "createdAt": { "type": "string" }
            }
        }
    }
}

 ```

### Update State Location

This endpoint is used to update the details of a specific state location.

#### Request

- Method: PUT

- URL: `{{API_URL}}master/locations/states/update/6a473a93-3883-4bcb-8083-feb6af48ffc8`

- Body:

    - name (text, required): The full name of the state.

    - nameShort (text, required): The short name or abbreviation of the state.

    - countryId (text, required): The unique identifier of the country to which the state belongs.

    - longitude (number, required): The longitude coordinate of the state location.

    - latitude (number, required): The latitude coordinate of the state location.


#### Response

The response is in JSON format and follows the schema below:

``` json
{
  "type": "object",
  "properties": {
    "tittle": { "type": "string" },
    "message": { "type": "string" },
    "data": {
      "type": "object",
      "properties": {
        "id": { "type": "string" },
        "country": {
